<script setup>
    import {useStore} from 'vuex';
    import { computed, ref } from 'vue'
    import ReviewSection from '@/components/expert_panels/ReviewSection.vue'
    import ReviewMembership from '@/components/expert_panels/ReviewMembership.vue'
    import { formatDate } from '@/date_utils'
    import { htmlFromMarkdown } from '@/markdown-utils';
    import GeneCurationStatus from '@/components/expert_panels/GeneCurationStatus.vue'
    import VcepGeneList from '@/components/expert_panels/VcepGeneList.vue';

    const store = useStore();
    const group = computed(() => store.getters['groups/currentItemOrNew'])
    const expertPanel = computed(() => group.value.expert_panel);

    const activeTab = ref('published');

    const members = computed( () => {
        if (!group.value) {
            return [];
        }
        return group.value.members;
    });

    const basicInfo = computed(() => {
        return {
            type: group.value.type.display_name,
            long_base_name: expertPanel.value.long_base_name,
            short_base_name: expertPanel.value.short_base_name,
        }
    });
</script>

<template>
  <div class="space-y-4">
    <ReviewSection title="Basic Information" name="basic-info">
      <object-dictionary :obj="basicInfo" label-class="w-40 font-bold" />
      <dictionary-row label="CDWG" label-class="w-40 font-bold">
        {{ group.parent ? group.parent.name : '--' }}
      </dictionary-row>
    </ReviewSection>

    <ReviewSection title="Membership" name="membership">
      <ReviewMembership :members="members" />

      <div v-if="group.is_vcep_or_scvcep" class="mt-6">
        <h4>Expertise of {{ group.type.display_name }} members</h4>
        <blockquote class="markdown-preview" v-html="htmlFromMarkdown(expertPanel.membership_description)"></blockquote>
      </div>
    </ReviewSection>

    <ReviewSection title="Website Description" name="website-description">
      <blockquote v-html="htmlFromMarkdown(group.description)"></blockquote>
    </ReviewSection>

    <ReviewSection title="Scope" name="scope">
      <h3>Genes</h3>
      <div class="mb-6">
        <p v-if="group.is_gcep">
          {{ expertPanel.genes.map(g => g.gene_symbol).join(', ') }}
        </p>
        <GeneCurationStatus v-if="group.is_gcep" :genes="expertPanel.genes" :readonly="true" :editing="false" />
        <VcepGeneList v-if="group.is_vcep_or_scvcep" :group="group" :editing="false" />
      </div>

      <h3>Description of scope</h3>
      <blockquote class="markdown-preview" v-html="htmlFromMarkdown(expertPanel.scope_description)"></blockquote>
    </ReviewSection>

    <ReviewSection v-if="group.is_gcep" title="Plans" name="plans">
      <dictionary-row label="Selected protocol" label-class="w-48 font-bold">
        <div class="flex-none">
          {{ expertPanel.curation_review_protocol ? titleCase(expertPanel.curation_review_protocol.full_name) : null }}
          <p v-if="expertPanel.curation_review_protocol_id == 100" class="mt-1">
            <em>Details:</em> {{ expertPanel.curation_review_protocol_other }}
          </p>
        </div>
      </dictionary-row>
    </ReviewSection>

    <ReviewSection v-if="group.is_gcep" title="Attestations" name="attestations">
      <dictionary-row label="GCEP Attestation Signed" label-class="w-52 font-bold">
        {{ formatDate(expertPanel.gcep_attestation_date) }}
      </dictionary-row>
      <dictionary-row label="GCI Training Date" label-class="w-52 font-bold">
        {{ formatDate(expertPanel.gci_training_date) }}
      </dictionary-row>
      <dictionary-row label="NHGRI Attestation Signed" label-class="w-52 font-bold">
        {{ formatDate(expertPanel.nhgri_attestation_date) }}
      </dictionary-row>
    </ReviewSection>

    <ReviewSection
      v-if="group.is_vcep_or_scvcep"
      title="Attestations"
      name="attestations"
    >
      <dictionary-row
        label="Reanalysis and Discrepancy Resolution Attestation Signed"
        label-class="w-52 font-bold"
      >
        {{ formatDate(expertPanel.reanalysis_attestation_date) }}
      </dictionary-row>
      <dictionary-row label="NHGRI Attestation Signed" label-class="w-60 font-bold">
        {{ formatDate(expertPanel.nhgri_attestation_date) }}
      </dictionary-row>
    </ReviewSection>
  </div>
</template>
<style scoped>
.markdown-preview :deep(p) {
  margin: 0.5rem 0;
}

.markdown-preview :deep(ul) {
  list-style-type: disc;
  padding-left: 1.5rem;
  margin: 0.5rem 0;
}

.markdown-preview :deep(ol) {
  list-style-type: decimal;
  padding-left: 1.5rem;
  margin: 0.5rem 0;
}

.markdown-preview :deep(li) {
  display: list-item;
  margin: 0.25rem 0;
}

.markdown-preview :deep(strong) {
  font-weight: 600;
}

.markdown-preview :deep(em) {
  font-style: italic;
}
</style>